import java.io.IOException;

public class CommandInjectionFixed {

    public static void main(String[] args) throws IOException {
        String userInput = "example.com";

        // Sanitize user input
        if (!userInput.matches("[a-zA-Z0-9.-]+")) {
            System.err.println("Invalid input. Please provide a valid domain name.");
            return;
        }

        // Construct the command using ProcessBuilder
        ProcessBuilder pb = new ProcessBuilder("ping", userInput);

        // Start the process
        Process process = pb.start();

        // Reading the output of the command
        java.util.Scanner scanner = new java.util.Scanner(process.getInputStream());
        while (scanner.hasNextLine()) {
            System.out.println(scanner.nextLine());
        }
    }
}

